// APTO Character Images — auto-embedded
window.APTO_IMGS = {
  "char-fist": "data:image/png;base64,",
  "char-flag": "data:image/png;base64,",
  "char-standing": "data:image/png;base64,",
  "char-suit-arms": "data:image/png;base64,",
  "char-suit-flag": "data:image/png;base64,",
  "char-suit-point-right": "data:image/png;base64,",
  "char-suit-point-up": "data:image/png;base64,",
  "char-point-right": "data:image/png;base64,",
  "char-point-up": "data:image/png;base64,",
  "char-suit-fist": "data:image/png;base64,",
};

document.addEventListener("DOMContentLoaded", function() {
  document.querySelectorAll("img[data-char]").forEach(function(img) {
    var key = img.getAttribute("data-char");
    if (window.APTO_IMGS[key]) img.src = window.APTO_IMGS[key];
  });
});
